    46→
    47→const log = logger.module('Notes');
    48→
    49→/**
    50→ * Recursive Folder Tree Node Component
    51→ */
    52→interface FolderTreeNodeProps {
    53→  node: any;
    54→  depth: number;
    55→  activeFolderId: string | null;
    56→  expandedFolderIds: Set<string>;
    57→  onSelect: (id: string) => void;
    58→  onToggleExpanded: (id: string) => void;
    59→  onDelete: (id: string, name: string) => void;
    60→  onRename: (id: string, name: string) => void;
    61→  getFolderNoteCount: (id: string) => number;
    62→}
    63→
    64→const FolderTreeNode: React.FC<FolderTreeNodeProps> = ({
    65→  node,
    66→  depth,
    67→  activeFolderId,
    68→  expandedFolderIds,
    69→  onSelect,
    70→  onToggleExpanded,
    71→  onDelete,
    72→  onRename,
    73→  getFolderNoteCount,
    74→}) => {
    75→  const isExpanded = expandedFolderIds.has(node.id);
    76→  const hasChildren = node.children && node.children.length > 0;
    77→  const noteCount = getFolderNoteCount(node.id);
    78→
    79→  return (
    80→    <div>
    81→      <div
    82→        className={`group relative rounded-lg transition-all duration-standard ${
    83→          activeFolderId === node.id
    84→            ? 'bg-accent-cyan bg-opacity-10 dark:bg-accent-magenta dark:bg-opacity-10'
    85→            : 'hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated hover:shadow-sm'
    86→        }`}
    87→        style={{ paddingLeft: `${depth * 16}px` }}
    88→      >
    89→        <div className="flex items-center">
    90→          {/* Expand/collapse button */}
    91→          {hasChildren && (
    92→            <button
    93→              onClick={(e) => {
    94→                e.stopPropagation();
    95→                onToggleExpanded(node.id);
    96→              }}
    97→              className="p-1 hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated rounded transition-colors"
    98→            >
    99→              {isExpanded ? (
   100→                <ChevronDown className="w-4 h-4 text-text-light-secondary dark:text-text-dark-secondary" />
   101→              ) : (
   102→                <ChevronRight className="w-4 h-4 text-text-light-secondary dark:text-text-dark-secondary" />
   103→              )}
   104→            </button>
   105→          )}
   106→          {!hasChildren && <span className="w-6" />}
   107→
   108→          {/* Folder button */}
   109→          <button
   110→            onClick={() => onSelect(node.id)}
   111→            className={`flex-1 text-left px-3 py-2 transition-all duration-standard flex items-center gap-2 ${
   112→              activeFolderId === node.id
   113→                ? 'text-accent-cyan dark:text-accent-magenta font-medium'
   114→                : 'text-text-light-secondary dark:text-text-dark-secondary group-hover:text-text-light-primary dark:group-hover:text-text-dark-primary'
   115→            }`}
   116→          >
   117→            {hasChildren ? (
   118→              isExpanded ? (
   119→                <FolderOpen className="w-4 h-4" />
   120→              ) : (
   121→                <Folder className="w-4 h-4" />
   122→              )
   123→            ) : (
   124→              <FileText className="w-4 h-4" />
   125→            )}
   126→            <span>{node.name}</span>
   127→            {noteCount > 0 && (
   128→              <span className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
   129→                ({noteCount})
   130→              </span>
   131→            )}
   132→          </button>
   133→
   134→          {/* Action buttons */}
   135→          <div className="absolute right-2 opacity-0 group-hover:opacity-100 flex gap-1 transition-opacity">
   136→            <button
   137→              onClick={(e) => {
   138→                e.stopPropagation();
   139→                onRename(node.id, node.name);
   140→              }}
   141→              className="p-1 hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated rounded transition-colors"
   142→              title="Rename folder"
   143→            >
   144→              <Edit2 className="w-4 h-4 text-text-light-secondary dark:text-text-dark-secondary" />
   145→            </button>
   146→            <button
   147→              onClick={(e) => {
   148→                e.stopPropagation();
   149→                onDelete(node.id, node.name);
   150→              }}
   151→              className="p-1 hover:bg-red-100 dark:hover:bg-red-900 rounded text-red-600 transition-colors"
   152→              title="Delete folder"
   153→            >
   154→              <Trash2 className="w-4 h-4" />
   155→            </button>
   156→          </div>
   157→        </div>
   158→      </div>
   159→
   160→      {/* Children */}
   161→      {isExpanded && hasChildren && (
   162→        <div className="ml-4">
   163→          {node.children.map((child: any) => (
   164→            <FolderTreeNode
   165→              key={child.id}
   166→              node={child}
   167→              depth={depth + 1}
   168→              activeFolderId={activeFolderId}
   169→              expandedFolderIds={expandedFolderIds}
   170→              onSelect={onSelect}
   171→              onToggleExpanded={onToggleExpanded}
   172→              onDelete={onDelete}
   173→              onRename={onRename}
   174→              getFolderNoteCount={getFolderNoteCount}
   175→            />
   176→          ))}
   177→        </div>
   178→      )}
   179→    </div>
   180→  );
   181→};
   182→
   183→/**
   184→ * Folder Sidebar Component (Simplified for MVP)
   185→ */
   186→const FolderSidebar: React.FC<{
   187→  activeTags: string[];
   188→  onAddTag: (tag: string) => void;
   189→  onRemoveTag: (tag: string) => void;
   190→  onClearAllTags: () => void;
   191→  onOpenTagManager: () => void;
   192→}> = ({ activeTags, onAddTag, onRemoveTag, onClearAllTags, onOpenTagManager }) => {
   193→  // Get raw folders object (stable reference unless folders change)
   194→  const foldersObj = useFoldersStore((state) => state.folders);
   195→  const activeFolderId = useFoldersStore((state) => state.activeFolderId);
   196→  const setActiveFolder = useFoldersStore((state) => state.setActiveFolder);
   197→  const createFolder = useFoldersStore((state) => state.createFolder);
   198→  const deleteFolder = useFoldersStore((state) => state.deleteFolder);
   199→  const updateFolder = useFoldersStore((state) => state.updateFolder);
   200→  const notesObj = useNotesStore((state) => state.notes);
   201→  const searchNotes = useNotesStore((state) => state.searchNotes);
   202→
   203→  // Dialog state
   204→  const [deleteDialogOpen, setDeleteDialogOpen] = useState(false);
   205→  const [renameDialogOpen, setRenameDialogOpen] = useState(false);
   206→  const [selectedFolderId, setSelectedFolderId] = useState<string | null>(null);
   207→  const [selectedFolderName, setSelectedFolderName] = useState('');
   208→
   209→  // Search state
   210→  const [searchQuery, setSearchQuery] = useState('');
   211→  const searchInputRef = useRef<HTMLInputElement>(null);
   212→
   213→  // Keyboard shortcut for search (Cmd+K)
   214→  useEffect(() => {
   215→    const handleKeyDown = (e: KeyboardEvent) => {
   216→      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
   217→        e.preventDefault();
   218→        searchInputRef.current?.focus();
   219→      }
   220→    };
   221→
   222→    window.addEventListener('keydown', handleKeyDown);
   223→    return () => window.removeEventListener('keydown', handleKeyDown);
   224→  }, []);
   225→
   226→  // Get tree structure for nested folders
   227→  const getTree = useFoldersStore((state) => state.getTree);
   228→  const toggleExpanded = useFoldersStore((state) => state.toggleExpanded);
   229→  const expandedFolderIds = useFoldersStore((state) => state.expandedFolderIds);
   230→
   231→  const folderTree = useMemo(() => getTree(), [foldersObj, getTree]);
   232→
   233→  // Get note count for a folder
   234→  const getFolderNoteCount = (folderId: string) => {
   235→    return Object.values(notesObj).filter(note => note.folderId === folderId).length;
   236→  };
   237→
   238→  // Handle folder deletion
   239→  const handleDeleteFolder = (folderId: string, folderName: string) => {
   240→    setSelectedFolderId(folderId);
   241→    setSelectedFolderName(folderName);
   242→    setDeleteDialogOpen(true);
   243→  };
   244→
   245→  const confirmDeleteFolder = () => {
   246→    if (!selectedFolderId) return;
   247→
   248→    // Save folder and notes for undo
   249→    const folderToDelete = foldersObj[selectedFolderId];
   250→    if (!folderToDelete) {
   251→      log.warn('Folder not found', { folderId: selectedFolderId });
   252→      return;
   253→    }
   254→
   255→    const notesToDelete = Object.values(notesObj).filter(note => note.folderId === selectedFolderId);
   256→    const noteCount = notesToDelete.length;
   257→
   258→    // Delete all notes in this folder (without undo since folder undo will handle it)
   259→    // We need to temporarily bypass the undo system for individual notes
   260→    notesToDelete.forEach(note => {
   261→      // Call the store action directly without triggering undo
   262→      useNotesStore.setState((state) => {
   263→        const { [note.id]: deleted, ...remainingNotes } = state.notes;
   264→        return {
   265→          notes: remainingNotes,
   266→          activeNoteId: state.activeNoteId === note.id ? null : state.activeNoteId,
   267→        };
   268→      });
   269→    });
   270→
   271→    // Delete the folder
   272→    deleteFolder(selectedFolderId);
   273→
   274→    log.info(`Folder "${folderToDelete.name}" deleted`, { noteCount });
   275→
   276→    // Add undo action to restore folder AND notes
   277→    useUndoStore.getState().addUndoAction(
   278→      `Folder "${folderToDelete.name}" and ${noteCount} note(s) deleted`,
   279→      () => {
   280→        // Restore the folder
   281→        useFoldersStore.setState((state) => ({
   282→          folders: {
   283→            ...state.folders,
   284→            [folderToDelete.id]: folderToDelete,
   285→          },
   286→        }));
   287→
   288→        // Restore all notes
   289→        useNotesStore.setState((state) => {
   290→          const restoredNotes = { ...state.notes };
   291→          notesToDelete.forEach(note => {
   292→            restoredNotes[note.id] = note;
   293→          });
   294→          return {
   295→            notes: restoredNotes,
   296→          };
   297→        });
   298→
   299→        log.info(`Folder "${folderToDelete.name}" and ${noteCount} note(s) restored (undo)`);
   300→      }
   301→    );
   302→  };
   303→
   304→  // Handle folder rename
