   490→  // Handle PDF export with loading state
   491→  const handlePDFExport = async (e: React.MouseEvent) => {
   492→    e.stopPropagation();
   493→    setIsExporting(true);
   494→    try {
   495→      await exportNoteToPDF(note, (filename) => {
   496→        setExportSuccess(filename);
   497→        setTimeout(() => setExportSuccess(null), 3000); // Clear after 3s
   498→      });
   499→    } catch (error) {
   500→      log.error('PDF export failed', { error });
   501→    } finally {
   502→      setIsExporting(false);
   503→    }
   504→  };
   505→
   506→  // Format date
   507→  const formatDate = (date: Date) => {
   508→    const now = new Date();
   509→    const diff = now.getTime() - new Date(date).getTime();
   510→    const days = Math.floor(diff / (1000 * 60 * 60 * 24));
   511→
   512→    if (days === 0) return 'Today';
   513→    if (days === 1) return 'Yesterday';
   514→    if (days < 7) return `${days} days ago`;
   515→    return new Date(date).toLocaleDateString();
   516→  };
   517→
   518→  // First line of content
   519→  const preview = note.contentText.split('\n')[0] || 'No content';
