   532→        <div className="absolute -top-8 left-0 right-0 bg-green-500 text-white text-xs py-1 px-2 rounded shadow-lg z-10 text-center flex items-center justify-center gap-1">
   533→          <Check className="w-3 h-3" />
   534→          Exported: {exportSuccess}
   535→        </div>
   536→      )}
   537→
   538→      {/* Main layout: Vertical actions on left + Content on right */}
   539→      <div className="flex items-start gap-2">
   540→        {/* Vertical action column - appears on left side on hover */}
   541→        <div className="flex flex-col gap-1 opacity-0 group-hover:opacity-100 transition-opacity duration-200 shrink-0 w-6">
   542→          <button
   543→            onClick={(e) => {
