   553→            onClick={handlePDFExport}
   554→            disabled={isExporting}
   555→            className="p-1 hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated rounded transition-all duration-150 hover:scale-110 disabled:opacity-50 disabled:cursor-not-allowed disabled:hover:scale-100"
   556→            title={isExporting ? 'Exporting...' : 'Export to PDF'}
   557→          >
   558→            {isExporting ? (
   559→              <Loader2 className="w-4 h-4 text-text-light-secondary dark:text-text-dark-secondary animate-spin" />
