   595→            className="p-1 hover:bg-red-100 dark:hover:bg-red-900 rounded text-red-600 transition-all duration-150 hover:scale-110"
   596→            title="Delete"
   597→          >
   598→            <Trash2 className="w-4 h-4" />
   599→          </button>
   600→        </div>
   601→
   602→        {/* Content area - No truncation needed with vertical actions */}
   603→        <div className="flex-1 min-w-0">
   604→          {/* Title row with static indicators */}
