    message: 'text-red-800 dark:text-red-400',
  },
  warning: {
    background: 'bg-yellow-50 dark:bg-yellow-900/20',
    border: 'border-yellow-400 dark:border-yellow-600',
    icon: 'text-yellow-600 dark:text-yellow-400',
    title: 'text-yellow-900 dark:text-yellow-300',
    message: 'text-yellow-800 dark:text-yellow-400',
  },
  info: {
    background: 'bg-blue-50 dark:bg-blue-900/20',
    border: 'border-blue-400 dark:border-blue-600',
    icon: 'text-blue-600 dark:text-blue-400',
    title: 'text-blue-900 dark:text-blue-300',
    message: 'text-blue-800 dark:text-blue-400',
  },
};

const sizeConfig = {
  sm: {
    padding: 'p-3',
    icon: 'w-5 h-5',
    title: 'text-sm',
    message: 'text-xs',
    button: 'text-xs px-2 py-1',
  },
  md: {
    padding: 'p-4',
    icon: 'w-6 h-6',
    title: 'text-base',
    message: 'text-sm',
    button: 'text-sm px-3 py-1.5',
  },
  lg: {
    padding: 'p-6',
    icon: 'w-8 h-8',
    title: 'text-xl',
    message: 'text-base',
    button: 'text-base px-4 py-2',
  },
};

/**
 * ErrorMessage - Comprehensive error display component with retry and details
 *
 * @example
 * // Simple error
 * <ErrorMessage
 *   title="Import Failed"
 *   message="The ICS file could not be imported. Please check the file format and try again."
 *   onRetry={() => retryImport()}
 * />
 *
 * @example
 * // With technical details
 * <ErrorMessage
 *   title="Connection Error"
 *   message="Failed to connect to the server"
 *   details={error.stack}
 *   onRetry={() => reconnect()}
 * />
 *
 * @example
 * // Warning variant
 * <ErrorMessage
 *   variant="warning"
 *   title="Storage Almost Full"
 *   message="You've used 90% of your browser storage. Consider exporting and deleting old data."
 * />
 */
export const ErrorMessage: React.FC<ErrorMessageProps> = ({
  title,
  message,
  details,
  onRetry,
  onDismiss,
  variant = 'error',
  size = 'md',
  className = '',
}) => {
  const [showDetails, setShowDetails] = useState(false);

  const variantStyles = variantConfig[variant];
  const sizeStyles = sizeConfig[size];

  return (
    <div
      className={`${sizeStyles.padding} ${variantStyles.background} ${variantStyles.border} border-2 rounded-lg ${className}`}
      role="alert"
    >
      <div className="flex items-start gap-3">
        {/* Icon */}
        <AlertCircle className={`${sizeStyles.icon} ${variantStyles.icon} flex-shrink-0 mt-0.5`} />

        {/* Content */}
        <div className="flex-1 min-w-0">
          {/* Title */}
          <h3 className={`${sizeStyles.title} font-bold ${variantStyles.title} mb-1`}>
            {title}
          </h3>

          {/* Message */}
          <p className={`${sizeStyles.message} ${variantStyles.message}`}>
            {message}
          </p>

          {/* Technical Details (Collapsible) */}
          {details && (
            <div className="mt-3">
              <button
                onClick={() => setShowDetails(!showDetails)}
                className={`${sizeStyles.button} flex items-center gap-1 ${variantStyles.message} hover:opacity-75 transition-opacity font-medium`}
              >
                {showDetails ? (
                  <>
                    <ChevronUp className="w-4 h-4" />
                    Hide details
                  </>
                ) : (
                  <>
                    <ChevronDown className="w-4 h-4" />
                    Show details
                  </>
                )}
              </button>

              {showDetails && (
                <div className="mt-2 p-3 bg-surface-light dark:bg-surface-dark-elevated rounded border border-border-light dark:border-border-dark overflow-auto max-h-40">
                  <pre className="text-xs text-text-light-secondary dark:text-text-dark-secondary whitespace-pre-wrap break-words font-mono">
                    {details}
                  </pre>
                </div>
              )}
            </div>
          )}

          {/* Actions */}
          {(onRetry || onDismiss) && (
            <div className="flex items-center gap-2 mt-4">
              {onRetry && (
                <button
                  onClick={onRetry}
                  className={`${sizeStyles.button} inline-flex items-center gap-1 ${variantStyles.message} bg-white dark:bg-surface-dark hover:opacity-75 border border-current rounded transition-opacity font-medium`}
                >
                  <RefreshCw className="w-4 h-4" />
                  Retry
                </button>
              )}
              {onDismiss && (
                <button
                  onClick={onDismiss}
                  className={`${sizeStyles.button} ${variantStyles.message} hover:opacity-75 transition-opacity`}
                >
                  Dismiss
                </button>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

